// Try both body locations - handles both raw and parsed webhook data
const body = items[0].json.body || items[0].json || {};

// Extract all fields with fallbacks
const client_name = body.client_name || "Unknown Client";
const category = body.category || "CRM";
const raw_requirement_text = body.raw_requirement_text || "";
const budget_range = body.budget_range || "Not specified";
const deadline_preference = body.deadline_preference || "Not specified";

// Build structured prompt — client_name is BAKED INTO the expected JSON response
// so Ollama will return it back to us and we won't lose it!
const prompt = `
You are an AI Product Manager.

Generate a structured product brief for the following client request:

Client Name: ${client_name}
Category: ${category}
Requirements: ${raw_requirement_text}
Budget: ${budget_range}
Timeline: ${deadline_preference}

Return ONLY valid JSON in this exact format with NO extra text:

{
  "client_name": "${client_name}",
  "category": "string",
  "features": ["string"],
  "sub_features": ["string"],
  "description": "string"
}
`;

return [{
  json: {
    client_name,
    category,
    raw_requirement_text,
    budget_range,
    deadline_preference,
    prompt
  }
}];

