const ollamaResponse = items[0].json.response;
const client_name = items[0].json.client_name || "";

let jsonStr = ollamaResponse;
jsonStr = jsonStr.replace(/```json\n?/g, '').replace(/```/g, '').trim();

const start = jsonStr.indexOf('{');
const end = jsonStr.lastIndexOf('}');
if (start !== -1 && end !== -1) {
  jsonStr = jsonStr.substring(start, end + 1);
}

let parsed;
try {
  parsed = JSON.parse(jsonStr);
} catch (e) {
  parsed = {
    category: "CRM",
    features: ["Order Tracking", "Customer Database", "Reporting"],
    sub_features: ["Dashboard", "Analytics", "Notifications"],
    description: "AI-generated product brief"
  };
}

return [{
  json: {
    client_name:  parsed.client_name || client_name,
    category:     parsed.category    || "CRM",
    features:     parsed.features    || [],
    sub_features: parsed.sub_features || [],
    description:  parsed.description  || ""
  }
}];

